member.example:
Bind the AudioSource bypassEffects property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceBypassEffectsBinder _bypassEffects;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _bypassEffects;
    }


Bind the AudioSource bypassEffects property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSource _audioSource;
        
        private AudioSourceBypassEffectsBinder BypassEffects =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _bypassEffects;
    }
